SELECT 
FROM check_record_appeals_new
WHERE 1=1

    AND record_id = #{recordId}


    AND class_id = #{classId}


    AND status = #{status}


    AND appellant_role = #{appellantRole}

ORDER BY
    CASE WHEN status IN (0, 1) THEN 0 ELSE 1 END,
    created_at DESC

SELECT 
FROM check_record_appeals_new
WHERE appellant_id = #{appellantId}
ORDER BY created_at DESC

    LIMIT #{limit}

SELECT 
FROM check_record_appeals_new
WHERE handler_id = #{handlerId}
ORDER BY handle_time DESC

    LIMIT #{limit}

SELECT COUNT(*)
FROM check_record_appeals_new
WHERE record_id = #{recordId}

    AND status = #{status}

SELECT EXISTS(
    SELECT 1 FROM check_record_appeals_new
    WHERE deduction_id = #{deductionId}
)
